test.config:
indexer
{
	mem_limit			= 28M
}

searchd
{

}

source auth
{
	type			= mysql

	sql_query_pre = SET NAMES UTF8
}

source src1 : auth
{
	sql_query = SELECT id, text FROM test_table WHERE id<2
}

source src2 : auth
{
	sql_query = SELECT id, text FROM test_table WHERE id>=2 AND id<4
}

source src3 : auth
{
	sql_query = SELECT id, text FROM test_table WHERE id>=4
}

index idx1
{
	source			= src1
	path			= /idx1
}

index idx2
{
	source			= src2
	path			= /idx2
}

index idx3
{
	source			= src3
	path			= /idx3
}

index dist0
{
	type					= distributed
	agent					= :idx3
}

index dist1
{
	type					= distributed
	local					= idx1
	agent					= :idx2
}

index dist2
{
	type					= distributed
	local					= idx1
	agent					= :dist0
}

index dist3
{
	type					= distributed
	local					= idx1
	local = idx2
	local = idx3
}

queries.sphinxql:
select * from idx1 order by id asc;
select * from idx2 order by id asc;
select * from idx3 order by id asc;
select * from dist0 order by id asc;
select * from dist1 order by id asc;
select * from dist2 order by id asc;
select * from dist3 order by id asc;
